import{_ as t,o,c as r,ag as a}from"./chunks/framework.BObsM2R8.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1781685456000}'),n={name:"getting-started/index.md"};function s(i,e,d,c,l,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>hapic</strong> — short for &quot;<strong>H</strong>TTP <strong>API</strong> <strong>C</strong>lient&quot; — is a tiny, <a href="https://developer.mozilla.org/en-US/docs/Web/API/Fetch_API" target="_blank" rel="noreferrer"><code>fetch</code></a>-based HTTP client for TypeScript. It wraps the platform <code>fetch</code> with the ergonomics you reach for in every real project, and nothing you don&#39;t:</p><blockquote><p>Method shortcuts, a <code>baseURL</code>, request/response/error hooks, body &amp; header transformers, authorization helpers, proxy support, and automatic error throwing on non-2xx responses.</p></blockquote><p>It runs unchanged in <strong>Node.js</strong>, the <strong>browser</strong>, and <strong>worker</strong> runtimes, and ships both ESM and CommonJS builds.</p><h2 id="two-layers" tabindex="-1">Two layers <a class="header-anchor" href="#two-layers" aria-label="Permalink to &quot;Two layers&quot;">​</a></h2><p>hapic is built in two layers, and you can use either:</p><table tabindex="0"><thead><tr><th>Layer</th><th>What it is</th></tr></thead><tbody><tr><td><strong><code>hapic</code></strong></td><td>The base <code>Client</code> — a thin, typed wrapper around <code>fetch</code> that owns the whole request lifecycle.</td></tr><tr><td><strong><code>@hapic/*</code></strong></td><td>A family of service clients (<code>harbor</code>, <code>oauth2</code>, <code>vault</code>, <code>loki</code>, <code>victorialogs</code>) that <strong>extend</strong> the base <code>Client</code> with typed, domain-oriented APIs.</td></tr></tbody></table><p>Every service client reuses the same transport, hooks, and instance registry — so once you know the base <code>Client</code>, you know all of them.</p><h2 id="why-hapic" tabindex="-1">Why hapic? <a class="header-anchor" href="#why-hapic" aria-label="Permalink to &quot;Why hapic?&quot;">​</a></h2><ul><li>You want <strong><code>fetch</code> semantics</strong> with a few quality-of-life additions, not a megabyte of abstraction.</li><li>You want <strong>non-2xx responses to throw</strong>, with a typed <code>ClientError</code> carrying the request, response, and status.</li><li>You want <strong>hooks</strong> that can not only observe but <em>recover</em> — return a <code>Response</code> to swallow an error, or new <code>RequestOptions</code> to retry (token refresh in a few lines).</li><li>You want the <strong>same client</strong> to run in Node, the browser, and edge/worker runtimes.</li><li>You&#39;re talking to <strong>Harbor, Vault, Loki, VictoriaLogs, or an OAuth2 provider</strong> and want a typed client instead of hand-rolled URLs.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/getting-started/installation">Installation</a> — install the base client or a service package.</li><li><a href="/getting-started/quick-start">Quick Start</a> — make your first request and handle an error.</li><li><a href="/guide/client">Guide → The Client</a> — every configuration option, in detail.</li><li><a href="/packages/">Packages</a> — pick a typed client for the service you run.</li></ul>',12)])])}const g=t(n,[["render",s]]);export{p as __pageData,g as default};
